GLOSSARY = {
"Bloodwork": ("Аналіз крові", "Лабораторний тест, під час якого береться та аналізується зразок крові, щоб перевірити наявність захворювань, недоліків або функціонування органів."),
"Anemia": ("Анемія", "Стан, коли в крові не вистачає здорових червоних кров’яних тілець, щоб переносити достатню кількість кисню до тканин організму."),
"Weight gain": ("Набір ваги", "Збільшення маси тіла, яке може бути наслідком затримки рідини, накопичення жиру або росту м’язів."),
"Weight loss": ("Втрата ваги", "Зниження маси тіла, яке може бути навмисним через дієту та фізичні вправи або ненавмисним через хворобу."),
"High blood pressure": ("Високий кров'яний тиск", "Також називається гіпертонією. Стан, коли сила тиску крові на стінки артерій постійно надто висока, що підвищує ризик серцевих захворювань та інсульту."),
"Low blood pressure": ("Низький кров'яний тиск", "Також називається гіпотонією. Стан, коли артеріальний тиск занадто низький, що може викликати запаморочення або непритомність."),
"Diabetes": ("Діабет", "Хронічний стан, при якому організм не може належним чином регулювати рівень цукру в крові через недостатнє вироблення інсуліну або інсулінорезистентність."),
"Cholesterol": ("Холестерин", "Жирова речовина в крові. Високий рівень поганого холестерину може блокувати артерії та збільшити ризик серцевих захворювань."),
"Blood sugar": ("Рівень цукру в крові", "Концентрація глюкози в крові. Контроль за цим необхідний для лікування діабету."),
"Heart rate": ("Частота серцевих скорочень", "Кількість ударів серця за хвилину. Нормальна частота спокою становить від 60 до 100 ударів на хвилину."),
"Pulse": ("Пульс", "Ритмічне пульсування артерій, спричинене серцебиттям, яке відчувається на зап’ясті або шиї."),
"Fever": ("Лихоманка", "Підвищення температури тіла вище 38 градусів за Цельсієм, як правило, є ознакою того, що організм бореться з інфекцією."),
"Nausea": ("Нудота", "Неприємні відчуття в шлунку з позивами до блювоти, часто є симптомом хвороби, прийому ліків або заколисування."),
"Vomiting": ("Блювання", "Сильне виштовхування вмісту шлунка через рот, зазвичай викликане хворобою, інфекцією або ковтанням токсинів."),
"Diarrhea": ("Діарея", "Часті, рідкі або водянисті випорожнення, часто викликані інфекцією, харчовою непереносимістю або прийомом ліків."),
"Constipation": ("Запор", "Утруднене випорожнення, що характеризується рідкісним, твердим або болючим стільцем."),
"Fatigue": ("Втома", "Постійна втома або виснаження, які не знімаються під час відпочинку, часто є симптомом основного захворювання."),
"Shortness of breath": ("Задишка", "Утруднене дихання або відчуття неможливості отримати достатньо повітря. Може бути симптомом захворювання серця або легенів."),
"Chest pain": ("Біль у грудях", "Біль або дискомфорт у грудній клітці, який може варіюватися від тупого болю до гострого колючого відчуття. Потенційний симптом серцевого нападу."),
"Rash": ("Висип", "Ділянка роздратованої або набряклої шкіри, часто червона та свербляча. Може бути викликано алергією, інфекцією або захворюваннями шкіри."),
"Swelling": ("Набряк", "Аномальне збільшення частини тіла через накопичення рідини в тканинах, що часто вказує на запалення або травму."),
"Infection": ("Інфекція", "Вторгнення та розмноження шкідливих мікроорганізмів, таких як бактерії, віруси або грибки, в організмі."),
"Inflammation": ("Запалення", "Захисна реакція організму на травму або інфекцію, що характеризується почервонінням, набряком, жаром і болем."),
"Fracture": ("Перелом", "Перелом кістки, починаючи від волосяної тріщини до повного розлому."),
"Sprain": ("Розтягнення", "Пошкодження зв’язки, тканини, яка з’єднує кістки, спричинене надмірним розтягуванням або розривом."),
"Allergy": ("Алергія", "Перебільшена імунна відповідь на зазвичай нешкідливу речовину, таку як пилок, їжа або ліки."),
"Asthma": ("Астма", "Хронічний стан, який спричиняє запалення та звуження дихальних шляхів, утруднюючи дихання."),
"Cancer": ("Рак", "Захворювання, при якому аномальні клітини неконтрольовано діляться і можуть проникати в сусідні тканини або поширюватися на інші частини тіла."),
"Stroke": ("Інсульт", "Невідкладна медична допомога, коли припиняється кровопостачання частини мозку, що спричиняє відмирання клітин мозку та потенційно призводить до паралічу або проблем з мовленням."),
"Heart attack": ("Серцевий напад", "Невідкладна медична допомога, коли потік крові до частини серця блокується, що спричиняє пошкодження серцевого м’яза."),
"Seizure": ("Судоми", "Раптове неконтрольоване електричне порушення в мозку, яке може спричинити судоми, втрату свідомості або незвичайну поведінку."),
"Migraine": ("Мігрень", "Сильний періодичний головний біль, часто з одного боку голови, що супроводжується нудотою, блювотою та чутливістю до світла чи звуку."),
"Arthritis": ("Артрит", "Запалення одного або кількох суглобів, що викликає біль, скутість і набряк. Поширені типи включають остеоартрит і ревматоїдний артрит."),
"Pregnancy": ("Вагітність", "Стан виношування дитини, що розвивається в матці, триває приблизно 40 тижнів."),
"Miscarriage": ("Викидень", "Спонтанна втрата вагітності до 20-го тижня, часто через хромосомні аномалії."),
"Discharge": ("Виділення", "Рідина, яка витікає з частини тіла, наприклад носа, піхви або рани. Може бути нормою або ознакою інфекції."),
"Urine": ("Сеча", "Рідкі відходи, які виробляються нирками та зберігаються в сечовому міхурі перед видаленням з організму."),
"Stool": ("Кал", "Тверді відходи виводяться з організму через кишечник. Також називають калом."),
"X-ray": ("Рентген", "Тип зображення, який використовує випромінювання для створення зображень кісток і певних тканин всередині тіла."),
"MRI": ("МРТ", "Магнітно-резонансна томографія. Сканування, яке використовує магнітні поля та радіохвилі для отримання детальних зображень органів і тканин."),
"Ultrasound": ("УЗД", "Техніка візуалізації, яка використовує звукові хвилі для створення зображень структур усередині тіла, зазвичай використовується під час вагітності."),
"Biopsy": ("Біопсія", "Медична процедура, під час якої невеликий зразок тканини вилучається з тіла та досліджується під мікроскопом для виявлення захворювання."),
"Surgery": ("Хірургічна операція", "Медична процедура, що включає розріз тіла для лікування, відновлення або видалення хворого або пошкодженого органу чи тканини."),
"Anesthesia": ("Анестезія", "Ліки, які використовуються для запобігання болю під час хірургічних операцій або процедур, шляхом знеболювання певної ділянки або тимчасового втратіння свідомості."),
"Wound": ("Рана", "Травма тіла, спричинена порізом, проколом або іншою травмою, яка розриває шкіру або підлеглі тканини."),
"Sutures": ("Шви", "Шви, які використовуються для закриття рани або хірургічного розрізу, що дозволяє тканині заживати належним чином."),
"Catheter": ("Катетер", "Тонка гнучка трубка, яка вставляється в тіло для відведення рідини, наприклад сечі, із сечового міхура або для доставки ліків."),
"IV (Intravenous)": ("Внутрішньовенне введення", "Метод доставки рідини, ліків або поживних речовин безпосередньо у вену через маленьку голку або трубку."),
"Vaccination": ("Вакцинація", "Введення вакцини для стимуляції імунної системи для захисту від конкретного інфекційного захворювання."),
"Immunization": ("Імунізація", "Процес, за допомогою якого людина захищається від хвороби за допомогою вакцинації."),
"Blood type": ("Група крові", "Класифікація крові, заснована на наявності або відсутності специфічних антигенів на еритроцитах. Основні типи: A, B, AB і O."),
"Platelet": ("Тромбоцит", "Крихітна клітина крові, яка допомагає згортатися крові, щоб зупинити кровотечу, коли кровоносну судину пошкоджено."),
"White blood cell": ("Лейкоцит", "Клітина крові, яка є частиною імунної системи. Це допомагає організму боротися з інфекціями та хворобами."),
"Red blood cell": ("Еритроцит", "Клітина крові, яка містить гемоглобін і переносить кисень від легень до решти тіла."),
"Hemoglobin": ("Гемоглобін", "Білок в еритроцитах, який переносить кисень. Низький рівень гемоглобіну свідчить про анемію."),
"Antibiotic": ("Антибіотик", "Препарат, який вбиває або пригнічує ріст бактерій. Він не працює проти вірусів."),
"Antiviral": ("Противірусний препарат", "Препарат, який використовується для лікування вірусних інфекцій шляхом припинення розмноження вірусу."),
"Anti-inflammatory": ("Протизапальний препарат", "Препарат, який зменшує запалення та пов’язаний з ним біль, наприклад ібупрофен."),
"Painkiller": ("Знеболюючий препарат", "Препарат, який використовується для зняття болю. Також називається анальгетиком."),
"Insulin": ("Інсулін", "Гормон, що виробляється підшлунковою залозою, який регулює рівень цукру в крові. Людям з діабетом часто потрібні ін'єкції інсуліну."),
"Blood pressure cuff": ("Тонометр", "Медичний пристрій для вимірювання артеріального тиску, що складається з надувної манжети, накладеної на руку."),
"Stethoscope": ("Стетоскоп", "Медичний інструмент, який використовується для прослуховування внутрішніх звуків тіла, наприклад серцебиття та дихання."),
"Thermometer": ("Термометр", "Пристрій для вимірювання температури тіла."),
"Oxygen": ("Кисень", "Необхідний для життя газ. У медичних установах додатковий кисень дають пацієнтам, які не можуть дихати належним чином самостійно."),
"Ventilator": ("Апарат штучної вентиляції легенів", "Апарат, який дихає для пацієнта, який не може дихати самостійно, доставляючи повітря та кисень через трубку."),
"Intubation": ("Інтубація", "Процедура, при якій трубка вставляється в дихальні шляхи через рот або ніс, щоб допомогти пацієнту дихати."),
"CPR": ("Серцево-легенева реанімація", "Серцево-легенева реанімація. Екстрена процедура, яка поєднує натискання грудної клітки та відновне дихання для підтримки кровообігу після зупинки серця."),
"AED": ("Автоматичний зовнішній дефібрилятор", "Автоматичний зовнішній дефібрилятор. Портативний пристрій, який подає електричний удар для відновлення нормального серцевого ритму під час зупинки серця."),
"Emergency": ("Невідкладна допомога", "Серйозна, несподівана ситуація, яка вимагає негайної медичної допомоги."),
"ICU": ("Відділення інтенсивної терапії", "Відділення інтенсивної терапії. Спеціалізована стаціонарна палата для пацієнтів у важкому стані, які потребують постійного спостереження."),
"ER (Emergency Room)": ("Відділення швидкої допомоги", "Відділення лікарні, що надає невідкладну допомогу при невідкладних і загрозливих для життя станах."),
"Ambulance": ("Швидка допомога", "Транспортний засіб, обладнаний медичним обладнанням, який використовується для екстреного транспортування пацієнтів до лікарні."),
"Discharge (hospital)": ("Виписка зі стаціонару", "Формальний процес виписки пацієнта з лікарні після завершення лікування."),
"Referral": ("Направлення до спеціаліста", "Рекомендація лікаря первинної медичної допомоги пацієнту звернутися до спеціаліста для подальшого обстеження або лікування."),
"Prescription": ("Рецепт", "Письмовий наказ від ліцензованого медичного працівника, який дозволяє пацієнту отримати ліки."),
"CAT scan (Computer Axial Tomography)": ("КТ — комп'ютерна аксіальна томографія", "Також називається КТ. Процедура візуалізації, яка використовує рентгенівські промені та комп’ютерну обробку для створення детальних зображень поперечного перерізу тіла."),
"DPT (Diphtheria, Pertussis, Tetanus)": ("АКДП — дифтерія, кашлюк, правець", "Комбінована вакцина, яка захищає від трьох серйозних бактеріальних захворювань: дифтерії, кашлюку та правця."),
"PCOS (Polycystic Ovarian Syndrome)": ("СПКЯ — синдром полікістозних яєчників", "Гормональний розлад, поширений серед жінок репродуктивного віку, що характеризується нерегулярними менструаціями та кістами на яєчниках."),
"COPD (Chronic Obstructive Pulmonary Disease)": ("ХОЗЛ — хронічне обструктивне захворювання легенів", "Хронічне запальне захворювання легенів, яке спричиняє утруднений потік повітря з легенів, зазвичай викликане тривалим курінням."),
"EKG/ECG (Electrocardiogram)": ("ЕКГ — електрокардіограма", "Тест, який реєструє електричну активність серця, використовується для виявлення серцевих проблем."),
"BMI (Body Mass Index)": ("ІМТ — індекс маси тіла", "Показник жиру в організмі на основі зросту та ваги. Використовується для класифікації осіб із недостатньою вагою, нормальною вагою, надмірною вагою або ожирінням."),
"BP (Blood Pressure)": ("АТ — артеріальний тиск", "Тиск циркулюючої крові на стінки кровоносних судин. Вимірюється як систолічний над діастолічним, наприклад, 120 на 80."),
"HR (Heart Rate)": ("ЧСС — частота серцевих скорочень", "Кількість ударів серця за хвилину. Використовується для оцінки стану серцево-судинної системи."),
"CBC (Complete Blood Count)": ("ЗАК — загальний аналіз крові", "Аналіз крові, який вимірює рівень червоних кров’яних тілець, білих кров’яних тілець і тромбоцитів, дає огляд загального стану здоров’я."),
"UTI (Urinary Tract Infection)": ("ІСШ — інфекція сечовивідних шляхів", "Інфекція будь-якої частини сечовидільної системи, включаючи нирки, сечовий міхур або уретру. Викликає часте, хворобливе сечовипускання."),
"STI (Sexually Transmitted Infection)": ("ІПСШ — інфекція, що передається статевим шляхом", "Інфекція, яка поширюється переважно статевим шляхом, наприклад хламідіоз, гонорея або сифіліс."),
"HIV (Human Immunodeficiency Virus)": ("ВІЛ — вірус імунодефіциту людини", "Вірус, який атакує імунну систему. Якщо не лікувати, це може призвести до СНІДу."),
"AIDS (Acquired Immunodeficiency Syndrome)": ("СНІД — синдром набутого імунодефіциту", "Найбільш запущена стадія ВІЛ-інфекції, при якій імунна система серйозно зруйнована і організм не може боротися з інфекціями."),
"TB (Tuberculosis)": ("ТБ — туберкульоз", "Серйозна бактеріальна інфекція, яка переважно вражає легені, поширюється через повітря, коли інфікована людина кашляє або чхає."),
"GI (Gastrointestinal)": ("ШКТ — шлунково-кишковий тракт", "Що стосується шлунка і кишечника. Шлунково-кишкові проблеми включають такі захворювання, як виразка, хвороба Крона та синдром подразненого кишечника."),
"OB/GYN (Obstetrics/Gynecology)": ("Акушерство та Гінекологія", "Медична спеціальність, що охоплює вагітність і пологи, а також жіночу репродуктивну систему."),
"Brand Name": ("Торгова назва", "Комерційна назва препарату виробником. Наприклад, Тайленол є торговою маркою ацетамінофену."),
"Generic Name": ("Міжнародна непатентована назва", "Офіційна непатентована назва препарату. Загальні версії містять той самий активний інгредієнт, що й фірмові препарати, але зазвичай дешевші."),
"Over-the-Counter (OTC)": ("Безрецептурний препарат", "Ліки, які можна придбати без рецепта, наприклад аспірин або ліки від застуди."),
"Dosage": ("Дозування", "Конкретна кількість і частота прийому ліків. Наприклад, по 500 міліграм двічі на день."),
"Side Effects": ("Побічні ефекти", "Непередбачені ефекти, викликані ліками на додаток до їх передбачуваного ефекту. Наприклад, сонливість, викликана антигістамінними препаратами."),
"Drug Interactions": ("Взаємодія ліків", "Коли два або більше ліків приймаються разом, змінюється дія кожного препарату, потенційно спричиняючи шкідливі наслідки."),
"Refill": ("Поповнення рецепту", "Додатковий запас ліків за рецептом, дозволеним лікарем і відпущеним в аптеці."),
"Pharmacy": ("Аптека", "Магазин або відділ, де відпускаються та продаються рецептурні та безрецептурні ліки."),
"Pharmacist": ("Фармацевт", "Ліцензований медичний працівник, який навчився видавати ліки та консультувати пацієнтів щодо їх безпечного використання."),
"Controlled Substance": ("Контрольована речовина", "Препарат, який регулюється державою через можливість зловживання ним або звикання. Для цього потрібні спеціальні рецепти."),
"Narcotics": ("Наркотичні речовини", "Потужні знеболювальні препарати, які можуть викликати звикання при неправильному вживанні, наприклад опіоїди. Це категорія контрольованих речовин."),
"Supplement": ("Харчова добавка", "Продукт, який використовується для додавання поживних речовин до раціону або для зниження ризику проблем зі здоров’ям, наприклад вітамінів, мінералів або рослинних продуктів."),
"Prescription (medication)": ("Рецептурний препарат", "Ліки, які потребують письмового дозволу лікаря та не можуть бути придбані без рецепта."),
"Annual Check-up": ("Щорічний медичний огляд", "Щорічне відвідування лікаря для загального огляду здоров’я, навіть якщо пацієнт не хворий."),
"Physical Exam": ("Фізикальний огляд", "Ретельний огляд лікаря з голови до ніг для оцінки загального стану здоров’я та виявлення будь-яких проблем."),
"Pap Smear": ("ПАП-тест", "Скринінговий тест на рак шийки матки у жінок, під час якого збирають і досліджують клітини шийки матки."),
"Mammogram": ("Мамографія", "Рентгенівський знімок молочної залози використовується для виявлення ранніх ознак раку молочної залози."),
"Colonoscopy": ("Колоноскопія", "Процедура, при якій гнучка камера вставляється в товсту кишку, щоб перевірити її на наявність поліпів, раку чи інших аномалій."),
"Eye Exam": ("Огляд очей", "Оцінка зору та здоров’я очей оптометристом або офтальмологом."),
"Dental Exam": ("Стоматологічний огляд", "Звичайна перевірка зубів, ясен і порожнини рота стоматологом для виявлення карієсу, захворювань ясен або інших проблем."),
"Well-Child Visit": ("Плановий педіатричний огляд", "Звичайний огляд дітей певного віку для моніторингу росту, розвитку та отримання щеплень."),
"Immunization Record": ("Карта вакцинації", "Документ із переліком усіх вакцин, які особа отримала, включаючи дати та типи."),
"Height and Weight": ("Зріст і вага", "Вимірювання, які регулярно проводяться під час медичних візитів для моніторингу росту та розрахунку ІМТ."),
"Blood Pressure Check": ("Вимірювання артеріального тиску", "Звичайне вимірювання сили тиску крові на стінки артерій за допомогою манжети для вимірювання артеріального тиску."),
"Urinalysis": ("Загальний аналіз сечі", "Лабораторне дослідження зразка сечі для виявлення ознак інфекції, захворювання нирок, діабету чи інших захворювань."),
"Cholesterol Test": ("Аналіз на холестерин", "Аналіз крові, що визначає рівень холестерину та тригліцеридів для оцінки ризику серцево-судинних захворювань."),
"Blood Glucose Test": ("Аналіз на глюкозу крові", "Тест, який вимірює кількість цукру в крові, використовується для діагностики та моніторингу діабету."),
"Prostate Exam": ("Дослідження простати", "Обстеження для перевірки здоров’я передміхурової залози у чоловіків, часто включає аналіз крові та медичний огляд."),
"Skin Cancer Screening": ("Скринінг раку шкіри", "Візуальний огляд шкіри дерматологом для виявлення підозрілих родимок або уражень, які можуть бути раковими."),
"STI Screening": ("Скринінг ІПСШ", "Регулярне тестування на інфекції, що передаються статевим шляхом, рекомендується сексуально активним людям."),
"Depression Screening": ("Скринінг депресії", "Анкета або оцінка, яка використовується для виявлення симптомів депресії та оцінки потреби в лікуванні."),
"Hearing Test": ("Тест на слух", "Оцінка слуху, яку проводить аудіолог для виявлення втрати слуху."),
"Bone Density Test": ("Денситометрія", "Сканування, яке вимірює міцність і щільність кісток, використовується для виявлення остеопорозу."),
"Thyroid Function Test": ("Аналіз функції щитовидної залози", "Аналіз крові, що визначає рівень гормонів щитовидної залози, щоб виявити такі захворювання, як гіпотиреоз або гіпертиреоз."),
"Vitamin D Level": ("Рівень вітаміну D", "Аналіз крові на визначення вітаміну D, необхідного для здоров’я кісток та імунної функції."),
"Iron Level": ("Рівень заліза", "Аналіз крові, який визначає рівень заліза в крові. Низький рівень заліза може призвести до анемії."),
"Liver Function Test": ("Аналіз функції печінки", "Аналіз крові, який перевіряє, наскільки добре працює печінка, шляхом вимірювання ферментів і білків, які вона виробляє."),
"Kidney Function Test": ("Аналіз функції нирок", "Аналіз крові або сечі, який перевіряє, наскільки добре нирки фільтрують відходи з крові."),
"Follow-up Appointment": ("Повторний прийом", "Запланований візит після первинного прийому або лікування для моніторингу прогресу або коригування лікування."),
"Medical History": ("Медична історія", "Запис про минулі хвороби людини, операції, ліки, алергію та стан здоров’я в сім’ї."),
"Vital Signs": ("Показники життєдіяльності", "Основні вимірювання функцій організму, включаючи температуру, пульс, частоту дихання та артеріальний тиск."),
"Internal medicine doctors": ("Лікарі внутрішньої медицини", "Лікарі, які спеціалізуються на профілактиці, діагностиці та лікуванні захворювань дорослих."),
"Pediatricians": ("Педіатри", "Лікарі, які спеціалізуються на охороні здоров'я та медичній допомозі немовлят, дітей та підлітків."),
"Family medicine doctors": ("Лікарі сімейної медицини", "Лікарі, які надають комплексну допомогу пацієнтам будь-якого віку, виступаючи в якості первинної медичної допомоги для сімей."),
"Obstetricians and gynecologists": ("Акушери-гінекологи", "Лікарі, що спеціалізуються на вагітності, пологах та жіночій репродуктивній системі."),
"Cardiologists": ("Кардіологи", "Фахівці з діагностики та лікування захворювань серця та серцево-судинної системи."),
"Orthopedic surgeons": ("Ортопедичні хірурги", "Хірурги, які лікують захворювання кісток, суглобів, зв’язок, сухожиль і м’язів."),
"Dermatologists": ("Дерматологи", "Лікарі, які займаються діагностикою та лікуванням захворювань шкіри, волосся та нігтів."),
"Ophthalmologists": ("Офтальмологи", "Лікарі, які спеціалізуються на лікуванні очей і зору, включаючи хірургію."),
"Psychiatrists": ("Психіатри", "Лікарі, які спеціалізуються на розладах психічного здоров’я, включаючи депресію, тривогу та шизофренію. Вони можуть призначити ліки."),
"Urologists": ("Урологи", "Лікарі, які лікують захворювання сечовивідних шляхів у чоловіків і жінок, а також чоловічу репродуктивну систему."),
"Neurologists": ("Неврологи", "Фахівці з захворювань головного, спинного мозку та нервової системи, таких як епілепсія, інсульт і хвороба Паркінсона."),
"Endocrinologists": ("Ендокринологи", "Лікарі, які лікують гормональні розлади, включаючи діабет, захворювання щитовидної залози та гормональний дисбаланс."),
"Gastroenterologists": ("Гастроентерологи", "Фахівці із захворювань органів травлення, зокрема шлунка, кишечника, печінки та підшлункової залози."),
"Rheumatologists": ("Ревматологи", "Лікарі, які лікують аутоімунні та запальні захворювання, що вражають суглоби, м’язи та кістки, такі як артрит і вовчак."),
"Pulmonologists": ("Пульмонологи", "Фахівці з захворювань легенів та дихальної системи, таких як астма, ХОЗЛ та пневмонія."),
"Oncologists": ("Онкологи", "Лікарі, які спеціалізуються на діагностиці та лікуванні раку."),
"Hematologists": ("Гематологи", "Фахівці з захворювань крові, зокрема анемії, проблем згортання крові та раку крові, як-от лейкемія."),
"Nephrologists": ("Нефрологи", "Лікарі, які спеціалізуються на захворюваннях нирок і таких станах, як хронічна хвороба нирок і ниркова недостатність."),
"Infectious disease specialists": ("Спеціалісти з інфекційних хвороб", "Лікарі, які займаються діагностикою та лікуванням складних інфекцій, викликаних бактеріями, вірусами, грибками або паразитами."),
"Allergists": ("Алергологи", "Лікарі, які займаються діагностикою та лікуванням алергії, астми та розладів імунної системи."),
"Immunologists": ("Імунологи", "Фахівці з розладів імунної системи, включаючи аутоімунні захворювання та імунодефіцитні стани."),
"Surgeons": ("Хірурги", "Лікарі, навчені виконувати операції для лікування травм, захворювань або деформацій."),
"Anesthesiologists": ("Анестезіологи", "Лікарі, які проводять анестезію та спостерігають за пацієнтами до, під час та після хірургічних процедур."),
"Radiologists": ("Радіологи", "Лікарі, які спеціалізуються на інтерпретації медичних зображень, таких як рентген, МРТ і КТ."),
"Pathologists": ("Патологоанатоми", "Лікарі, які досліджують зразки тканин у лабораторії для діагностики захворювань, зокрема раку."),
"Emergency medicine doctors": ("Лікарі швидкої допомоги", "Лікарі, які спеціалізуються на лікуванні невідкладних та небезпечних для життя станів у відділенні невідкладної допомоги."),
"Physical therapists": ("Фізіотерапевти", "Медичні працівники, які допомагають пацієнтам відновити рух і справлятися з болем за допомогою вправ і фізичних процедур."),
"Occupational therapists": ("Ерготерапевти", "Терапевти, які допомагають пацієнтам відновити здатність виконувати повсякденну діяльність після хвороби чи травми."),
"Speech therapists": ("Логопеди", "Фахівці, які оцінюють та лікують розлади спілкування та проблеми з ковтанням."),
"Audiologists": ("Аудіологи", "Медичні працівники, які діагностують і лікують розлади слуху та рівноваги."),
"Optometrists": ("Оптометристи", "Окулісти, які перевіряють зір і призначають окуляри або контактні лінзи. Вони не лікарі."),
"Dentists": ("Стоматологи", "Медичні працівники, які займаються діагностикою та лікуванням захворювань зубів і порожнини рота."),
"Oral surgeons": ("Щелепно-лицьові хірурги", "Фахівці, які проводять операції на порожнині рота, щелепи та обличчя, включаючи видалення зубів і реконструкцію щелепи."),
"Orthodontists": ("Ортодонти", "Стоматологи, які виправляють нерівності зубів і щелепи за допомогою брекетів або елайнерів."),
"Chiropractors": ("Мануальні терапевти", "Медичні працівники, які лікують захворювання опорно-рухового апарату, головним чином шляхом маніпуляцій і коригування хребта."),
"Podiatrists": ("Подіатри", "Фахівці з захворювань стопи, гомілки та гомілки."),
"Dietitians/Nutritionists": ("Дієтологи та Нутриціоністи", "Експерти з продуктів харчування та харчування, які консультують пацієнтів щодо здорового харчування та контролюють стани, пов’язані з дієтою."),
"Social workers": ("Соціальні працівники", "Професіонали, які допомагають пацієнтам і родинам отримати доступ до ресурсів і послуг, а також надають консультаційну підтримку."),
"Psychologists": ("Психологи", "Фахівці з психічного здоров’я, які оцінюють і лікують психологічні розлади за допомогою терапії. На відміну від психіатрів, вони зазвичай не можуть призначати ліки."),
"Abrupt": ("Раптовий", "Раптовий початок. Біль починається дуже швидко без попередження."),
"Aching": ("Той, що болить", "Тупий, постійний біль, як біль у м’язах."),
"Acute": ("Гострий", "Сильний і короткочасний біль, зазвичай з раптовим початком."),
"Bearable": ("Терпимий", "Біль, який викликає дискомфорт, але який можна терпіти без ліків."),
"Burning": ("Пекучий", "Біль, який відчувається як жар або вогонь на шкірі або під шкірою."),
"Chronic": ("Хронічний", "Біль, що зберігається протягом тривалого часу, як правило, більше трьох місяців."),
"Constant": ("Постійний", "Біль, який не припиняється і не зникає. Завжди присутній."),
"Cramping": ("Судомний", "Стискаючий, стискаючий біль, спричинений скороченням м’язів, як судоми ніг або менструальний біль."),
"Crushing": ("Розчавлюючий", "Надзвичайно сильний, давить біль, часто пов’язаний із серцевим нападом."),
"Debilitating": ("Виснажливий", "Біль настільки сильний, що заважає людині нормально функціонувати."),
"Deep": ("Глибокий", "Біль, який відчувається всередині тіла, а не на поверхні."),
"Dull": ("Тупий", "Розлитий, не різкий біль низької інтенсивності."),
"Excruciating": ("Нестерпний", "Найсильніший рівень болю. Нестерпний і приголомшливий."),
"Intermittent": ("Переривчастий", "Біль, який виникає і зникає з інтервалами, а не постійний."),
"Lancinating": ("Стріляючий", "Різкий, ріжучий, колючий біль. Ніби порізаний ножем."),
"Localized": ("Локалізований", "Біль обмежена певною ділянкою тіла."),
"Mild": ("Легкий", "Біль слабкого рівня, який помітний, але суттєво не заважає повсякденній діяльності."),
"Moderate": ("Помірний", "Біль середньої інтенсивності. Помітний і впливає на щоденні функції, але не переважний."),
"Numbness": ("Оніміння", "Втрата чутливості або відчуття частини тіла."),
"Persistent": ("Стійкий", "Біль, який триває без полегшення."),
"Piercing": ("Пронизливий", "Інтенсивний, пронизуючий різкий біль."),
"Pins and needles": ("Поколювання", "Відчуття поколювання в частині тіла, ніби в неї встромляють маленькі шпильки, часто через уповільнений кровотік."),
"Pressure": ("Тиснучий", "Біль, який відчувається як щось тисне або стискає ззовні."),
"Pulsating": ("Пульсуючий", "Біль, який пульсує в ритмі серцебиття, як сильний зубний або головний біль."),
"Radiating": ("Іррадіюючий", "Біль, який поширюється від свого джерела до інших частин тіла, як біль у сідничному нерві, що рухається вниз по нозі."),
"Recurring": ("Повторний", "Біль, який зникає, а потім знову повертається."),
"Severe": ("Тяжкий", "Сильний біль, який значно впливає на повсякденне життя та потребує медичної допомоги."),
"Sharp": ("Гострий", "Раптовий, інтенсивний і чітко виражений біль, схожий на поріз."),
"Shooting": ("Стріляючий", "Біль, який швидко поширюється по нерву, як удар електричним струмом."),
"Sore": ("Болючий", "Чутливість або біль у м’язі чи ділянці тіла, особливо після травми або надмірного навантаження."),
"Spasmodic": ("Спазматичний", "Біль, що виникає при раптових мимовільних скороченнях м’язів."),
"Stabbing": ("Колючий", "Раптовий, гострий, сильний біль, схожий на удар ножем."),
"Stinging": ("Пекучий", "Різкий, поверхневий пекучий біль, схожий на укус бджоли."),
"Tender": ("Чутливий до дотику", "Біль, що виникає при дотику або натисканні на уражену ділянку."),
"Throbbing": ("Пульсуючий", "Спираючий або стукаючий біль, який посилюється з кожним ударом серця."),
"Tingling": ("Поколювання", "Легке поколювання або поколювання, схоже на поколювання."),
"Unbearable": ("Нестерпний", "Біль занадто сильний, щоб його терпіти без медичного втручання."),
"Vague": ("Невизначений", "Біль, який важко точно описати або точно визначити."),
"Wandering": ("Блукаючий", "Біль, що переходить з одного місця на тіло в інше."),
"Worsening": ("Наростаючий", "Біль, яка з часом посилюється."),
"Clavicle": ("Ключиця", "Ключиця. Довга кістка, яка з’єднує плече з грудиною."),
"Femur": ("Стегнова кістка", "Стегнова кістка. Найдовша і міцна кістка в організмі людини."),
"Fibula": ("Мала гомілкова кістка", "Найтонша з двох кісток гомілки, що проходить уздовж великогомілкової кістки."),
"Humerus": ("Плечова кістка", "Кістка плеча, що з’єднує плече з ліктем."),
"Patella": ("Колінна чашечка", "Колінна чашечка. Маленька плоска кістка в передній частині колінного суглоба."),
"Pelvis": ("Таз", "Кісткова структура в основі хребта, яка підтримує органи черевної порожнини."),
"Scapula": ("Лопатка", "Лопатка. Плоска трикутна кістка на задній частині плеча."),
"Skull": ("Череп", "Кісткова структура, яка охоплює та захищає мозок."),
"Spine": ("Хребет", "Хребет або хребетний стовп. Ряд кісток, які захищають спинний мозок і підтримують тіло."),
"Sternum": ("Грудина", "Грудна кістка. Плоска кістка в центрі грудей."),
"Tibia": ("Велика гомілкова кістка", "Гомілкова кістка. Більша з двох кісток гомілки."),
"Achilles tendon": ("Ахіллесове сухожилля", "Велике сухожилля, що з’єднує литковий м’яз з п’ятковою кісткою. Найміцніше сухожилля в організмі."),
"Ligament": ("Зв'язка", "Міцна смуга волокнистої тканини, яка з’єднує кістки з іншими кістками в суглобі."),
"Tendon": ("Сухожилля", "Міцний шнур із волокнистої тканини, який з’єднує м’яз із кісткою."),
"Aorta": ("Аорта", "Найбільша артерія в тілі, яка переносить збагачену киснем кров від серця до решти тіла."),
"Artery": ("Артерія", "Кровоносна судина, яка переносить збагачену киснем кров від серця до тканин тіла."),
"Vein": ("Вена", "Кровоносна судина, яка переносить дезоксигеновану кров назад до серця."),
"Appendix": ("Апендикс", "Невеликий мішечок, прикріплений до товстого кишечника. Його точна функція невідома, але запалення викликає апендицит."),
"Colon": ("Товста кишка", "Товста кишка. Він поглинає воду з перевареної їжі і передає відходи в пряму кишку."),
"Esophagus": ("Стравохід", "М'язова трубка, що з'єднує горло зі шлунком, через яку проходить їжа."),
"Gallbladder": ("Жовчний міхур", "Невеликий орган під печінкою, який зберігає жовч, рідину, яка допомагає перетравлювати жири."),
"Liver": ("Печінка", "Найбільший внутрішній орган. Він фільтрує кров, виробляє жовч і переробляє поживні речовини."),
"Pancreas": ("Підшлункова залоза", "Залоза, яка виробляє травні ферменти та інсулін для регулювання рівня цукру в крові."),
"Stomach": ("Шлунок", "М'язовий орган, який отримує їжу зі стравоходу і починає процес травлення."),
"Bladder": ("Сечовий міхур", "Порожнистий орган у малому тазу, який зберігає сечу, доки вона не буде виведена з організму."),
"Kidney": ("Нирка", "Один із двох бобоподібних органів, які фільтрують відходи з крові та виробляють сечу."),
"Ovary": ("Яєчник", "Один із двох жіночих репродуктивних органів, які виробляють яйцеклітини та гормони естроген і прогестерон."),
"Prostate": ("Простата", "Залоза в чоловічій репродуктивній системі, яка виробляє рідину, що живить сперму."),
"Thyroid": ("Щитовидна залоза", "Залоза у формі метелика на шиї, яка виробляє гормони, що регулюють обмін речовин."),
"Uterus": ("Матка", "Утроба. Орган у жіночому тазі, де розвивається плід під час вагітності."),
"Lung": ("Легеня", "Один із двох органів у грудній клітці, що відповідає за газообмін, доставку кисню в кров і видалення вуглекислого газу."),
"Trachea": ("Трахея", "Трахея. Трубка, яка переносить повітря від горла до легенів."),
"Brain": ("Мозок", "Орган усередині черепа, який контролює всі функції тіла, мислення, пам’ять та емоції."),
"Spinal cord": ("Спинний мозок", "Пучок нервів, що проходить через хребет, передає сигнали між мозком і тілом."),
"Cornea": ("Рогівка", "Прозорий передній шар ока, який покриває райдужну оболонку та зіницю."),
"Retina": ("Сітківка", "Світлочутливий шар у задній частині ока, який посилає візуальні сигнали в мозок."),
"Lymph node": ("Лімфатичний вузол", "Маленькі бобоподібні залози, які фільтрують лімфатичну рідину та є частиною імунної системи."),
"Spleen": ("Селезінка", "Орган, який фільтрує кров і відіграє роль у імунній функції."),
"Skin (dermis)": ("Шкіра — дерма", "Зовнішній покрив тіла. Найбільший орган, що захищає від травм, інфекцій і перепадів температури."),
"Ankle": ("Кісточка", "Суглоб, що з’єднує стопу з гомілкою."),
"Elbow": ("Лікоть", "Суглоб між плечем і плечем."),
"Knee": ("Коліно", "Суглоб між гомілкою і гомілкою."),
"Shoulder": ("Плече", "Суглоб, у якому рука з’єднується з тілом."),
"Wrist": ("Зап'ясток", "Суглоб між кистю і передпліччям."),
"Hip": ("Стегно", "Суглоб, де стегнова кістка стикається з тазом."),
"Heel": ("П'ята", "Задня частина стопи."),
"ACA (Affordable Care Act)": ("Закон про доступну медичну допомогу", "Федеральний закон США, прийнятий у 2010 році, розширив доступ до медичного страхування та додав захист споживачів."),
"Allowed Amount": ("Дозволена сума", "Максимальна сума, яку страховий план заплатить за послугу, що покривається. Пацієнт може заборгувати різницю."),
"Coinsurance": ("Співстрахування", "Відсоток витрат, який пацієнт сплачує після виконання своєї франшизи. Наприклад, 20% співстрахування означає, що пацієнт платить 20%, а страховик – 80%."),
"Copayment (Copay)": ("Співплата", "Частка витрат на медичне обслуговування, яку оплачує пацієнт, включаючи франшизи, доплати та співстрахування."),
"Cost Sharing": ("Розподіл витрат", "Частка витрат на медичне обслуговування, яку оплачує пацієнт, включаючи франшизи, доплати та співстрахування."),
"Deductible": ("Франшиза", "Сума, яку пацієнт повинен сплачувати зі своєї кишені за медичні послуги щороку до того, як почне виплачуватися страховка."),
"Dependent": ("Залежний", "Особа, як правило, подружжя або дитина, яка охоплена програмою медичного страхування іншої особи."),
"Drug Formulary": ("Перелік лікарських препаратів", "Список ліків, що відпускаються за рецептом, на які поширюється страховий план, часто організований на рівні залежно від вартості."),
"Durable Medical Equipment (DME)": ("Медичне обладнання тривалого користування", "Обладнання, призначене лікарем для домашнього використання, наприклад інвалідні візки, кисневе обладнання або лікарняні ліжка."),
"EOB (Explanation of Benefits)": ("Пояснення щодо виплат", "Документ, надісланий страховою компанією після претензії, у якому пояснюється, що було покрито та що повинен пацієнт."),
"Essential Health Benefits": ("Основні медичні послуги", "Десять категорій послуг, які повинні покриватися планами, що продаються згідно з ACA, включаючи госпіталізацію, догляд за вагітними та психіатричні послуги."),
"Fee-for-Service (FFS)": ("Оплата за надані послуги", "Модель оплати, за якої постачальникам платять окремо за кожну надану послугу."),
"FSA (Flexible Spending Account)": ("Рахунок для гнучких витрат", "Спонсорований роботодавцем рахунок, на який працівники відкладають гроші до сплати податків для оплати відповідних медичних витрат."),
"Grace Period": ("Пільговий період", "Період часу після дати платежу, протягом якого страховий поліс залишається в силі, поки прострочений платіж все ще може бути здійснений."),
"HMO (Health Maintenance Organization)": ("Організація з підтримки здоров'я", "Тип плану медичного страхування, який вимагає від учасників використовувати мережу конкретних лікарів і отримувати направлення до спеціалістів."),
"HSA (Health Savings Account)": ("Рахунок медичних ощадних витрат", "Ощадний рахунок із пільговим сплатою оподаткування для осіб із планами охорони здоров’я з високою франшизою для заощаджень і оплати медичних витрат."),
"In-Network": ("Внутрішньомережеві", "Постачальники, які уклали договір страхування. Пацієнти платять менше за внутрішньомережеву допомогу."),
"Maximum Out-of-Pocket": ("Максимальна сума власних витрат", "Найбільше, що пацієнту доведеться заплатити за послуги, що покриваються, у плановому році. Після досягнення цього ліміту страховка покриває 100%."),
"Medically Necessary": ("Медична необхідність", "Медичні послуги або матеріали, необхідні для діагностики або лікування хвороби, травми чи стану."),
"Open Enrollment Period": ("Період відкритої реєстрації", "Конкретний період кожного року, коли люди можуть оформити або змінити свій план медичного страхування."),
"Out-of-Network": ("Позамережеві", "Постачальники, які не уклали договір страхування. Пацієнти зазвичай платять більше за позамережеву допомогу."),
"PCP (Primary Care Provider)": ("Постачальник первинної медичної допомоги", "Лікар, медична сестра або помічник лікаря, який надає загальну медичну допомогу та направляє пацієнтів до спеціалістів."),
"PPO (Preferred Provider Organization)": ("Організація пріоритетного постачальника", "Тип плану медичного обслуговування, який дозволяє пацієнтам звертатися до будь-якого лікаря без направлення, але коштує дешевше за умови використання постачальників у мережі."),
"Preauthorization (Precertification)": ("Попередня авторизація", "Потрібне схвалення страхової компанії перед отриманням певних медичних послуг або ліків."),
"Pre-Existing Condition": ("Наявний стан здоров'я", "Стан здоров’я, який існував до того, як пацієнт зареєстрований у плані медичного обслуговування. Згідно з ACA, страховики не можуть відмовити в покритті попередніх умов."),
"Premium": ("Страховий внесок", "Щомісячна сума, сплачена за медичне страхування, незалежно від того, чи користуються медичними послугами."),
"Prior Authorization": ("Попередня авторизація", "Потрібне схвалення від страховика, перш ніж можна буде покривати конкретну послугу, процедуру або ліки."),
"Special Enrollment Period": ("Спеціальний період реєстрації", "Час за межами відкритого періоду реєстрації, коли особа може підписатися на медичне страхування через кваліфіковану життєву подію, таку як шлюб або втрата роботи."),
"Subsidy": ("Субсидія", "Фінансова допомога, яку надає уряд, щоб допомогти особам з низькими доходами сплачувати внески медичного страхування."),
"Telehealth": ("Телемедицина", "Медичні послуги, що надаються дистанційно за допомогою технологій, як-от відеодзвінки або телефонні консультації з лікарем."),
"Medicaid": ("Medicaid", "Спільна федеральна та державна програма, яка забезпечує безкоштовне або недороге медичне страхування дорослим із низьким рівнем доходу, дітям, вагітним жінкам і людям з обмеженими можливостями."),
"Medicare": ("Medicare", "Федеральна програма медичного страхування для людей віком від 65 років і для деяких молодих людей з обмеженими можливостями."),
"Medicare Part A": ("Medicare Частина A", "Охоплює стаціонарну допомогу в стаціонарі, кваліфікований догляд у закладах догляду, хоспіси та деякі медичні послуги вдома."),
"Medicare Part B": ("Medicare Частина B", "Охоплює амбулаторне лікування, відвідування лікаря, профілактичні послуги та медичне обладнання."),
"Medicare Part C": ("Medicare Частина C — Medicare Advantage", "Альтернатива оригінальній програмі Medicare, яку пропонують приватні страховики, часто включає покриття ліків."),
"Medicare Part D": ("Medicare Частина D", "Додає до Medicare покриття ліків, що відпускаються за рецептом. Пропонується через приватні страховики."),
"Beneficiary": ("Бенефіціар — вигодонабувач", "Особа, яка охоплена та отримує виплати за планом страхування."),
"Coordination of Benefits (COB)": ("Координація виплат", "Процес, який використовується, коли пацієнт має два або більше планів медичного страхування, щоб визначити, який план платить першим і скільки платить кожен план."),
"Waiting Period": ("Період очікування", "Час між реєстрацією в плані медичного обслуговування та фактичним початком покриття."),
"Wellness Program": ("Програма оздоровлення", "Програма, запропонована роботодавцями або страховими компаніями для заохочення здорової поведінки, як-от завдання щодо фізичної форми або підтримка у відмові від куріння."),
}
